import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname } from "node:path";

const [, , inputPath = "docs/openapi.json", outputPath = "web/src/generated/api-types.ts"] = process.argv;

const document = JSON.parse(await readFile(inputPath, "utf8"));
const schemas = document.components?.schemas ?? {};

const lines = [
  "/* eslint-disable */",
  "// Generated by scripts/generate-openapi-types.mjs from docs/openapi.json.",
  "// Do not edit this file directly.",
  ""
];

for (const [name, schema] of Object.entries(schemas)) {
  lines.push(`export type ${name} = ${typeForSchema(schema)};`, "");
}

await mkdir(dirname(outputPath), { recursive: true });
await writeFile(outputPath, `${lines.join("\n")}\n`);

function typeForSchema(schema) {
  if (!schema) return "unknown";
  if (schema.$ref) return refName(schema.$ref);
  if (Array.isArray(schema.enum)) {
    return schema.enum.map((value) => JSON.stringify(value)).join(" | ") || "never";
  }
  if (Array.isArray(schema.oneOf)) return schema.oneOf.map(typeForSchema).join(" | ");
  if (Array.isArray(schema.anyOf)) return schema.anyOf.map(typeForSchema).join(" | ");
  if (Array.isArray(schema.allOf)) return schema.allOf.map(typeForSchema).join(" & ");

  const type = Array.isArray(schema.type) ? schema.type.filter((item) => item !== "null")[0] : schema.type;
  const base = typeForNonNullableSchema({ ...schema, type });
  return schema.nullable || (Array.isArray(schema.type) && schema.type.includes("null")) ? `${base} | null` : base;
}

function typeForNonNullableSchema(schema) {
  switch (schema.type) {
    case "string":
      return "string";
    case "integer":
    case "number":
      return "number";
    case "boolean":
      return "boolean";
    case "array":
      return `${typeForSchema(schema.items)}[]`;
    case "object":
      return objectType(schema);
    default:
      if (schema.properties || schema.additionalProperties) return objectType(schema);
      return "unknown";
  }
}

function objectType(schema) {
  const properties = schema.properties ?? {};
  const required = new Set(schema.required ?? []);
  const fields = Object.entries(properties).map(([name, propertySchema]) => {
    const optional = required.has(name) ? "" : "?";
    return `  ${JSON.stringify(name)}${optional}: ${typeForSchema(propertySchema)};`;
  });

  if (schema.additionalProperties) {
    fields.push(`  [key: string]: ${schema.additionalProperties === true ? "unknown" : typeForSchema(schema.additionalProperties)};`);
  }

  return fields.length === 0 ? "Record<string, unknown>" : `{\n${fields.join("\n")}\n}`;
}

function refName(ref) {
  const prefix = "#/components/schemas/";
  if (!ref.startsWith(prefix)) {
    throw new Error(`unsupported ref: ${ref}`);
  }
  return ref.slice(prefix.length);
}
